import React, { useState, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import './RolePlay.css';

const EXCEL_COLUMNS = [
  'Story_Title','Story_Category','JLPT_Level','Difficulty','Background_Image',
  'Character_Name','Character_Avatar','Character_Order',
  'Dialogue_Order','Japanese','Romaji','English','Word_Meaning',
  'Emotion','Pause_MS','Expected_Pronunciation','Audio_File',
];

const SAMPLE_ROWS = [
  {
    Story_Title:'Restaurant Conversation', Story_Category:'Daily Life', JLPT_Level:'N5', Difficulty:'Easy',
    Background_Image:'restaurant.jpg', Character_Name:'Customer', Character_Avatar:'customer.png',
    Character_Order:1, Dialogue_Order:1, Japanese:'こんにちは', Romaji:'Konnichiwa', English:'Hello',
    Word_Meaning:'こんにちは = Hello', Emotion:'Happy', Pause_MS:1000, Expected_Pronunciation:'こんにちは', Audio_File:'',
  },
  {
    Story_Title:'Restaurant Conversation', Story_Category:'Daily Life', JLPT_Level:'N5', Difficulty:'Easy',
    Background_Image:'restaurant.jpg', Character_Name:'Waiter', Character_Avatar:'waiter.png',
    Character_Order:2, Dialogue_Order:2, Japanese:'いらっしゃいませ', Romaji:'Irasshaimase', English:'Welcome',
    Word_Meaning:'いらっしゃいませ = Welcome', Emotion:'Polite', Pause_MS:1000, Expected_Pronunciation:'いらっしゃいませ', Audio_File:'',
  },
];

function ValidationPanel({ data }) {
  return (
    <div className="rp-validation-panel">
      <div className="rp-val-grid">
        <div className="rp-val-stat">
          <div className="rp-val-num" style={{ color: '#2D9D4A' }}>{data.rows}</div>
          <div className="rp-val-label">Rows Found</div>
        </div>
        <div className="rp-val-stat">
          <div className="rp-val-num" style={{ color: '#6366F1' }}>{data.characters}</div>
          <div className="rp-val-label">Characters</div>
        </div>
        <div className="rp-val-stat">
          <div className="rp-val-num" style={{ color: '#0EA5E9' }}>{data.dialogue}</div>
          <div className="rp-val-label">Dialogue Lines</div>
        </div>
        <div className="rp-val-stat">
          <div className="rp-val-num" style={{ color: data.errors > 0 ? '#BF1B2C' : '#2D9D4A' }}>{data.errors}</div>
          <div className="rp-val-label">Errors</div>
        </div>
        <div className="rp-val-stat">
          <div className="rp-val-num" style={{ color: data.warnings > 0 ? '#F59E0B' : '#2D9D4A' }}>{data.warnings}</div>
          <div className="rp-val-label">Warnings</div>
        </div>
      </div>

      {data.errors > 0 && (
        <div className="alert alert-error" style={{ marginTop: 12 }}>
          ⚠️ {data.errors} error(s) found. Please fix your Excel file before importing.
        </div>
      )}
      {data.warnings > 0 && (
        <div className="rp-warning-banner" style={{ marginTop: 8 }}>
          ⚡ {data.warnings} warning(s) — optional fields missing (Audio_File). Import will still succeed.
        </div>
      )}
    </div>
  );
}

export default function RolePlayImport() {
  const navigate = useNavigate();
  const fileRef = useRef(null);
  const [dragOver, setDragOver] = useState(false);
  const [file, setFile] = useState(null);
  const [phase, setPhase] = useState('idle'); // idle | validating | preview | importing | done | error

  const [validation, setValidation] = useState(null);

  const processFile = useCallback(async (f) => {
    setFile(f);
    setPhase('validating');
    await new Promise(r => setTimeout(r, 1400));
    // Mock validation result
    const rows = Math.floor(Math.random() * 20) + 6;
    setValidation({
      rows,
      characters: Math.floor(rows / 3) + 1,
      dialogue: rows,
      errors: 0,
      warnings: 1,
    });
    setPhase('preview');
  }, []);

  const handleDrop = useCallback((e) => {
    e.preventDefault();
    setDragOver(false);
    const f = e.dataTransfer.files[0];
    if (f && (f.name.endsWith('.xlsx') || f.name.endsWith('.xls'))) {
      processFile(f);
    } else {
      alert('Please upload an Excel (.xlsx or .xls) file.');
    }
  }, [processFile]);

  const handleBrowse = (e) => {
    const f = e.target.files[0];
    if (f) processFile(f);
  };

  const handleImport = async () => {
    setPhase('importing');
    await new Promise(r => setTimeout(r, 2000));
    setPhase('done');
  };

  const reset = () => {
    setFile(null);
    setPhase('idle');
    setValidation(null);
  };

  return (
    <div className="rp-page">
      <div className="rp-page-header">
        <div>
          <h2 className="rp-page-title">📊 Import Excel</h2>
          <p className="rp-page-sub">Upload an Excel file to automatically create stories, characters, and dialogue.</p>
        </div>
      </div>

      {/* DONE state */}
      {phase === 'done' && (
        <div className="rp-import-done">
          <div className="rp-done-icon">🎉</div>
          <h3>Import Successful!</h3>
          <div className="rp-done-stats">
            <div className="rp-done-stat"><span>{validation?.rows}</span><label>Rows</label></div>
            <div className="rp-done-stat"><span>{validation?.characters}</span><label>Characters</label></div>
            <div className="rp-done-stat"><span>{validation?.dialogue}</span><label>Dialogue Lines</label></div>
          </div>
          <div className="rp-done-checks">
            {['Story Created','Characters Imported','Dialogue Imported','Validation Passed'].map(c => (
              <div key={c} className="rp-done-check">✅ {c}</div>
            ))}
          </div>
          <div className="rp-done-actions">
            <button className="btn btn-secondary" onClick={reset}>Import Another</button>
            <button className="btn btn-primary" onClick={() => navigate('/roleplay/stories')}>Preview Stories</button>
          </div>
        </div>
      )}

      {/* Upload zone */}
      {(phase === 'idle') && (
        <div
          className={`rp-drop-zone ${dragOver ? 'drag-over' : ''}`}
          onDragOver={e => { e.preventDefault(); setDragOver(true); }}
          onDragLeave={() => setDragOver(false)}
          onDrop={handleDrop}
          onClick={() => fileRef.current.click()}
        >
          <div className="rp-drop-icon">📊</div>
          <div className="rp-drop-title">Drag & Drop Excel File Here</div>
          <div className="rp-drop-sub">or click to browse your computer</div>
          <button className="btn btn-primary rp-browse-btn" onClick={e => { e.stopPropagation(); fileRef.current.click(); }}>
            Browse Files
          </button>
          <div className="rp-drop-hint">Supported: .xlsx, .xls — Max 50MB</div>
          <input
            ref={fileRef}
            type="file"
            accept=".xlsx,.xls"
            style={{ display: 'none' }}
            onChange={handleBrowse}
          />
        </div>
      )}

      {/* Validating */}
      {phase === 'validating' && (
        <div className="rp-loading-card">
          <div className="rp-spinner" />
          <div className="rp-loading-text">Validating <strong>{file?.name}</strong>...</div>
          <div className="rp-loading-sub">Checking rows, characters, and dialogue structure</div>
        </div>
      )}

      {/* Preview */}
      {phase === 'preview' && validation && (
        <div>
          <div className="card" style={{ marginBottom: 20 }}>
            <div className="section-header" style={{ marginBottom: 16 }}>
              <h3>📋 Validation Results — {file?.name}</h3>
              <button className="btn btn-secondary btn-sm" onClick={reset}>Change File</button>
            </div>
            <ValidationPanel data={validation} />
          </div>

          {/* Preview table */}
          <div className="card" style={{ marginBottom: 20 }}>
            <div className="section-header" style={{ marginBottom: 12 }}>
              <h3>👁 Preview (first 2 rows)</h3>
            </div>
            <div className="table-wrap">
              <table>
                <thead>
                  <tr>
                    {['Character','Order','Japanese','Romaji','English','Emotion'].map(h => <th key={h}>{h}</th>)}
                  </tr>
                </thead>
                <tbody>
                  {SAMPLE_ROWS.map((r, i) => (
                    <tr key={i}>
                      <td style={{ fontWeight: 700 }}>{r.Character_Name}</td>
                      <td>{r.Dialogue_Order}</td>
                      <td style={{ fontFamily: 'serif', fontSize: 15 }}>{r.Japanese}</td>
                      <td style={{ color: 'var(--text-muted)' }}>{r.Romaji}</td>
                      <td>{r.English}</td>
                      <td><span className="badge badge-blue">{r.Emotion}</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="rp-import-actions">
            <button className="btn btn-secondary" onClick={reset}>Cancel</button>
            <button
              className="btn btn-primary rp-import-btn"
              onClick={handleImport}
              disabled={validation.errors > 0}
            >
              🚀 Import {validation.rows} Rows
            </button>
          </div>
        </div>
      )}

      {/* Importing */}
      {phase === 'importing' && (
        <div className="rp-loading-card">
          <div className="rp-spinner" />
          <div className="rp-loading-text">Importing data...</div>
          <div className="rp-loading-sub">Creating stories, characters and dialogue lines</div>
        </div>
      )}

      {/* Excel Format Reference */}
      {phase !== 'done' && (
        <div className="card" style={{ marginTop: 32 }}>
          <div className="section-header" style={{ marginBottom: 12 }}>
            <h3>📐 Required Excel Format</h3>
            <a
              href="#"
              className="btn btn-secondary btn-sm"
              onClick={e => e.preventDefault()}
            >
              ⬇ Download Template
            </a>
          </div>
          <p style={{ fontSize: 13, color: 'var(--text-muted)', marginBottom: 12 }}>
            Your Excel file must have <strong>one worksheet</strong> with the following columns:
          </p>
          <div className="rp-columns-grid">
            {EXCEL_COLUMNS.map(c => (
              <div key={c} className="rp-column-chip">{c}</div>
            ))}
          </div>

          <div className="table-wrap" style={{ marginTop: 16 }}>
            <table>
              <thead>
                <tr>
                  {['Story_Title','Character_Name','Character_Order','Dialogue_Order','Japanese','Romaji','English'].map(h => <th key={h}>{h}</th>)}
                </tr>
              </thead>
              <tbody>
                {SAMPLE_ROWS.map((r, i) => (
                  <tr key={i}>
                    <td>{r.Story_Title}</td>
                    <td style={{ fontWeight: 700 }}>{r.Character_Name}</td>
                    <td>{r.Character_Order}</td>
                    <td>{r.Dialogue_Order}</td>
                    <td style={{ fontFamily: 'serif' }}>{r.Japanese}</td>
                    <td>{r.Romaji}</td>
                    <td>{r.English}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}
